var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"괴, 굉장해요……!","JPN":"す、すごい……！","ENG":"A-amazing...!","TWN":"真，真是難以置信……！"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"밖에서 봤을 때는 무너져가는 유적이었는데 내부는 멀쩡하네요.","JPN":"外観は崩れかけの遺跡だったけど、内部はきれいなんですね。","ENG":"From outside it looked like a crumbling ruin, but the inside is intact.","TWN":"外面看起來是個破舊的遺跡，可內部卻很正常呢。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"생각했던 것보다는 좀 평범한데?","JPN":"思ったより普通やな。","ENG":"Kind of plain, isn't it?","TWN":"比我想像中要普通一些呢？"},"stage":{"bg":"CORRIDOR_08","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"내는 황금향 유적이라카면, 삐까번쩍할 줄 알았거든?","JPN":"黄金郷の遺跡っちゅうから、ウチはもっと派手なもんやと思ててん。","ENG":"When I heard Golden Vale ruins, I expected something flashy.","TWN":"我還以為黃金城遺跡會金光閃閃？"},"stage":{"bg":"CORRIDOR_08","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"아니, 유심히 보게나. 인디애나 GAP.","JPN":"いや、よく見るんじゃ、インディアナ-甲-。","ENG":"Look closer, Indiana G.A.P.","TWN":"不，你仔細看看，印第安納GAP。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"유적에 황금향 이끼가 잔뜩 끼어 있어. 분명, 누군가의 피가 닿으면 금빛으로 변할 걸세.","JPN":"遺跡に黄金郷の苔がたくさん生えておる。きっと、誰かの血に触れると金色に変わるじゃろう。","ENG":"The walls are covered in Golden Vale moss. If touched with blood, it will gleam gold.","TWN":"遺跡上滿是黃金城苔蘚。肯定沒錯，如果沾上某人的血液，就會變成金色。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"평생을 황금향의 전설을 연구하는데 바쳤어.","JPN":"ワシは黄金郷の伝説の研究に生涯を捧げた。","ENG":"I devoted my life to studying the legend of the Golden Vale.","TWN":"我一生都致力於研究黃金城的傳說。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그런 이 몸이 보증하지. 이곳은 틀림없는 전설 속의 황금향 유적이야.","JPN":"そのワシが保証しよう。ここは紛れもなく、伝説にある黄金郷の遺跡じゃ。","ENG":"I vouch for it. This is truly the legendary Golden Vale ruin.","TWN":"我可以保證，這裡無疑就是傳說中的黃金城遺跡。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"하지만 대체 이건……?","JPN":"しかし、これはいったい……？","ENG":"But what in the world is this...?","TWN":"但這到底是……？"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_OFF","text":{"KOREA":"도착했어요.","JPN":"着きました。","ENG":"We've arrived.","TWN":"到了。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"이, 이터니움이에요! 이렇게 많은 양은 처음 봐요!","JPN":"エ、エタニウムです！　こんなに大量のエタニウムは初めて見ます！","ENG":"I-it's Eternium! I've never seen this much before!","TWN":"這，這是永恆之晶！我從來沒見過這麼多！"},"stage":{"bg":"CORRIDOR_08","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"우와, 고급스러운 물건들이 잔뜩 있어요! 어디에 쓰는 물건일까요?","JPN":"うわあ、高級そうな物がたくさん……！　どこに使う物なんでしょう？","ENG":"Wow, all these luxurious relics! What could they be used for?","TWN":"哇，這裡有好多高級的東西！這些東西是用來做什麼的呢？"},"stage":{"bg":"CORRIDOR_08","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"마, 로빈아. 함부로 막 건들지 마라. 뭔가 쌔하다 이거.","JPN":"ロビン、不用意に触れたらあかん。嫌な予感がする。","ENG":"Robin, don't touch anything. Something doesn't feel right.","TWN":"喂，蘿蘋。別隨便亂碰。這東西有點不對勁。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"네? 무슨 말씀이세요?","JPN":"え？　どういうことですか？","ENG":"Huh? What do you mean?","TWN":"嗯？什麼意思？"},"stage":{"bg":"CORRIDOR_08","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"영감님은 이 공간에서 뭔가 위화감 같은 거 못 느꼈습니까?","JPN":"じじいはこの空間で何か違和感、感じんかった？","ENG":"Old man, don't you feel something off about this place?","TWN":"你不覺得這個空間有些不對勁嗎？"},"stage":{"bg":"CORRIDOR_08","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"자네도 느꼈군. 나도 이상하다고 생각하던 참이었네.","JPN":"おぬしも感づいていたか。ワシもおかしいと思っていたところじゃ。","ENG":"You feel it too. I was thinking the same.","TWN":"你也有感覺到嗎？我也正覺得奇怪呢。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"관리국 표준 매뉴얼에 따르면, 이터니움은 한 장소에 보관할 수 있는 양이 정해져 있네.","JPN":"管理局の標準マニュアルによると、1か所に保管できるエタニウムの量は限られておる。","ENG":"According to Administration protocol, there's a strict limit on how much Eternium can be stored in one place.","TWN":"根據管理局手冊，永恆之晶在一個地方的存放量是有限制的。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"많은 양의 이터니움이 한 곳에 모여 있으면, 차원 계면을 융해시켜 버리거든.","JPN":"大量のエタニウムが1か所に集まっていると、次元界面を融解させてしまうからのう。","ENG":"Too much Eternium dissolves the dimension surface.","TWN":"大量的永恆之晶聚集在一起，會融化次元介面。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"저 정도 양이라면, 진작에 차원 자체가 녹아뿌렸겠지예.","JPN":"あの量ならとっくに次元ごと溶けてたはずやで。","ENG":"With this much, the dimension should've melted down already.","TWN":"如果是這種程度的量，次元本身應該早就瓦解了吧。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"뭔가가 억지로 이 유적이 있는 공간을 붙들어 매고 있는 게 틀림없습니다.","JPN":"間違いない。何かが、この遺跡が存在する空間を無理やり留めてるんや。","ENG":"Something must be forcibly holding this ruin in place.","TWN":"一定有什麼東西強行將遺跡所在的空間固定住。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"그, 그렇게 말씀하시니까 뭔가 으스스한데요?","JPN":"そ、そう言われると何だかゾッとします。","ENG":"N-now that you say that, it feels eerie...","TWN":"你，你這麼說讓我有點心裡毛毛欸？"},"stage":{"bg":"CORRIDOR_08","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"니 말이 맞다. 으스스하지.","JPN":"ゾットする……その通りや。","ENG":"Exactly. Eerie.","TWN":"你說的沒錯。真是毛毛的。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"왠지 들어올 때부터 쌔했다. 마치 공간 자체에 누군가의 의지가 있는 것처럼…….","JPN":"入ってきた時からそうやった。空間そのものに誰かの意志があるような……","ENG":"It's felt wrong since we walked in, like someone's will is bound to the space itself...","TWN":"從進來的時候我就感覺有些不對勁，感覺空間本身有某種意志一樣……"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"그래, 꼭 카운터의 CRF와 비슷한 기운이라고 할까……?","JPN":"せやな、まるでカウンターのCRFに似ている気配や。","ENG":"It feels almost like a Counter's CRF...","TWN":"沒錯，和制裁者的CRF很類似……"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_OFF","text":{"KOREA":"맞아요.","JPN":"そうです。","ENG":"That's right.","TWN":"沒錯。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"맞아요. 원래라면 이 유적은 존재할 수 없거든요.","JPN":"そうです。本来ならこの遺跡は存在できません。","ENG":"\\"That's right. Normally, this ruin couldn't exist at all.\\"","TWN":"沒錯。按理說，這個遺跡本不該存在。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_DESPAIR"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"한 사람의 의지가 아주 오랫동안 이 유적을 유지시키고 있는 거죠.","JPN":"1人の意志が、長い間この遺跡を維持しているんです。","ENG":"\\"One person's will has been preserving it all this time.\\"","TWN":"是一個人的意志長時間維持著這片遺跡。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_DESPAIR"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"먼 훗날, 이 유적을 찾아낼 누군가를 간절히 기다리면서.","JPN":"遠い未来、この遺跡を見つけ出してくれる誰かを、待ち望んで。","ENG":"\\"Waiting desperately for someone to finally find it.\\"","TWN":"熱切地等待著未來有人能找到這處遺跡。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_DESPAIR"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"그리고 그 분이 저를 이곳으로 이끄셨어요.","JPN":"そして、その人が私をここへと導きました。","ENG":"\\"And that person guided me here.\\"","TWN":"而且是他把我引導到這裡來的。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_DESPAIR"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"……라고 시타 아가씨께서는 쓸쓸하게 답하십니다.","JPN":"……と、シータお嬢様が寂しげにおっしゃっています。","ENG":"...is what Lady Sita says, her voice tinging with sorrow.","TWN":"……悉多小姐如此說道。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_DESPAIR"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"유적을 지키고 있는 사람이 있다고요?","JPN":"遺跡を守っている人がいる？","ENG":"You're saying someone's guarding this ruin?","TWN":"有人在看守遺跡嗎？"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};